    "wizard_region_input": "Injiza cyawe state cyangwa region kuri localized urwego (e.g., 'California').",
    "wizard_search_btn": "Shakisha kuri urwego matching cyawe query na urwego rw'ishuri.",
    "wizard_search_result_link": "Kanda ku reba full urwego description na requirements.",
